"use strict";(self.webpackChunkmission_peak_resc=self.webpackChunkmission_peak_resc||[]).push([["601"],{3991(e){e.exports=JSON.parse('{"version":{"pluginId":"support","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"supportSidebar":[{"type":"link","href":"/support/","label":"Support Center","docId":"index","unlisted":false},{"type":"category","label":"Aurora","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/support/about-aurora","label":"About Aurora","docId":"aurora/about-aurora","unlisted":false}],"href":"/support/category/aurora"},{"type":"category","label":"Newsfeed","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/support/about-newsfeed","label":"About Newsfeed","docId":"newsfeed/about-newsfeed","unlisted":false}],"href":"/support/category/newsfeed"},{"type":"category","label":"Huddles","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/support/about-huddles","label":"About Huddles","docId":"huddles/about-huddles","unlisted":false},{"type":"link","href":"/support/huddle-privacy-options","label":"Huddle Privacy Options","docId":"huddles/huddle-privacy-options","unlisted":false},{"type":"link","href":"/support/huddle-payments-and-refunds","label":"Huddle Payments & Refunds","docId":"huddles/huddle-payments-and-refunds","unlisted":false},{"type":"link","href":"/support/huddle-advanced-settings","label":"Huddle Advanced Settings","docId":"huddles/huddle-advanced-settings","unlisted":false}],"href":"/support/category/huddles"},{"type":"category","label":"Communities","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/support/about-communities","label":"About Communities","docId":"communities/about-communities","unlisted":false},{"type":"link","href":"/support/community-privacy-options","label":"Community Privacy Options","docId":"communities/community-privacy-options","unlisted":false}],"href":"/support/category/communities"},{"type":"category","label":"Connections","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/support/about-connections","label":"About Connections","docId":"connections/about-connections","unlisted":false}],"href":"/support/category/connections"},{"type":"category","label":"Inspirations","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/support/about-inspirations","label":"About Inspirations","docId":"inspirations/about-inspirations","unlisted":false},{"type":"link","href":"/support/writing-inspiration","label":"How to Write and Publish an Inspiration","docId":"inspirations/writing-inspiration","unlisted":false}],"href":"/support/category/inspirations"},{"type":"category","label":"Account & Privacy","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/support/username-dob-changes","label":"Changing Your Username or Date of Birth","docId":"account/username-dob-changes","unlisted":false},{"type":"link","href":"/support/account-deletion","label":"How to Permanently Delete Your Account","docId":"account/account-deletion","unlisted":false}],"href":"/support/category/account--privacy"},{"type":"link","href":"/support/faq","label":"Frequently Asked Questions","docId":"faq","unlisted":false},{"type":"link","href":"/support/glossary","label":"Glossary of Terms","docId":"glossary","unlisted":false}]},"docs":{"account/account-deletion":{"id":"account/account-deletion","title":"How to Permanently Delete Your Account","description":"If you no longer wish to use MissionPeak, you can permanently delete your account at any time. Deleting your account will remove your profile and all associated data from our platform.","sidebar":"supportSidebar"},"account/username-dob-changes":{"id":"account/username-dob-changes","title":"Changing Your Username or Date of Birth","description":"To keep MissionPeak safe and trustworthy for everyone, usernames and dates of birth cannot be changed directly from the app or website. This helps us maintain accurate identity records and prevent misuse of the platform.","sidebar":"supportSidebar"},"aurora/about-aurora":{"id":"aurora/about-aurora","title":"About Aurora","description":"Aurora is your AI-powered outdoor companion in MissionPeak. Whether you\'re planning your next adventure, looking for activity ideas, or seeking guidance on health and wellness, Aurora is here to assist you every step of the way.","sidebar":"supportSidebar"},"communities/about-communities":{"id":"communities/about-communities","title":"About Communities","description":"Communities are where friendships grow, passions unite, and activities thrive on MissionPeak. Whether you\'re joining a hiking group, starting a local club, or building a space for your close friends, Communities give you the platform to connect and organize around shared interests.","sidebar":"supportSidebar"},"communities/community-privacy-options":{"id":"communities/community-privacy-options","title":"Community Privacy Options","description":"When you create a Community on MissionPeak, you choose a privacy level that controls who can find it and who can see what\'s inside. You can set or change this from the Community\'s settings.","sidebar":"supportSidebar"},"connections/about-connections":{"id":"connections/about-connections","title":"About Connections","description":"Connections help you build your social circle on MissionPeak by following and engaging with people who inspire you. Whether it\'s friends, fellow hikers, or outdoor influencers, Connections make it easy to stay updated with their activities and share your own journey.","sidebar":"supportSidebar"},"faq":{"id":"faq","title":"Frequently Asked Questions","description":"Answers to common questions about using MissionPeak.","sidebar":"supportSidebar"},"glossary":{"id":"glossary","title":"Glossary of Terms","description":"Common terms you\'ll come across while using MissionPeak, defined in one place.","sidebar":"supportSidebar"},"huddles/about-huddles":{"id":"huddles/about-huddles","title":"About Huddles","description":"Huddles are at the heart of MissionPeak \u2014 they\'re the way you create, join, and enjoy social activities with like-minded people. Whether you\'re looking to organize a group hike, a casual meetup, or a structured activity, Huddles make it easy to bring people together.","sidebar":"supportSidebar"},"huddles/huddle-advanced-settings":{"id":"huddles/huddle-advanced-settings","title":"Huddle Advanced Settings","description":"When creating a Huddle, hosts can configure a set of Advanced Settings that control how participants RSVP, how many people can join, and what other participants can see or do. These are separate from Advanced Features (currently just Carpooling) and from a Huddle\'s payment and refund details.","sidebar":"supportSidebar"},"huddles/huddle-payments-and-refunds":{"id":"huddles/huddle-payments-and-refunds","title":"Huddle Payments & Refunds","description":"Attending a Huddle can be free or paid, depending on how the host sets it up. This article explains how paid Huddles work on MissionPeak, how payments and refunds are handled, and what to expect as a host or an attendee.","sidebar":"supportSidebar"},"huddles/huddle-privacy-options":{"id":"huddles/huddle-privacy-options","title":"Huddle Privacy Options","description":"Every Huddle you create on MissionPeak has a privacy setting that controls who can see it, who can find it, and who can RSVP or participate. You choose this when creating the Huddle, and can adjust it from the Huddle\'s settings.","sidebar":"supportSidebar"},"index":{"id":"index","title":"Support Center","description":"Welcome to the MissionPeak Support Center. Browse guides for the core features of the app, or contact us directly if you need more help.","sidebar":"supportSidebar"},"inspirations/about-inspirations":{"id":"inspirations/about-inspirations","title":"About Inspirations","description":"On MissionPeak, Inspiration is more than just an article or blog post \u2014 it\'s your voice echoing across a community of outdoor explorers, wellness seekers, and changemakers. It\'s where your experience becomes someone else\'s motivation. Whether you\'re an adventurer, a health professional, or simply someone with a story to tell, Inspiration is your space to connect, uplift, and ignite action.","sidebar":"supportSidebar"},"inspirations/writing-inspiration":{"id":"inspirations/writing-inspiration","title":"How to Write and Publish an Inspiration","description":"Inspiration on MissionPeak is your way to share stories, hiking experiences, expert advice, or wellness journeys with the outdoor community. Whether you\'re a weekend hiker, nature lover, or health professional, your words can inspire and influence others. Here\'s a step-by-step guide to help you create and publish your first Inspiration.","sidebar":"supportSidebar"},"newsfeed/about-newsfeed":{"id":"newsfeed/about-newsfeed","title":"About Newsfeed","description":"Your Newsfeed is the central hub of MissionPeak. It\'s where you stay updated on everything happening in your network \u2014 Huddles, Communities, Inspirations, and updates from the people you follow. Think of it as your personal outdoor activity stream.","sidebar":"supportSidebar"}}}}')}}]);